={{(()=>{
  const st = $('read video status').last().json
  const lo = $('read session lock').last().json
  const re = $('Set Video Requirements').last().json

  const condition =
( re.requireText ?
  !st.textReady &&
  !lo.textLock : true
)

  return condition
})()}}

