// n8n Code node
// В rawText вставляешь РОВНО свой текст как есть.
// Ничего не парсится, ничего не чистится, комментарии сохраняются.
// Просто превращаем строку в binary-файл.

const rawText =
`{
    //##################################################################################
    //0. GENERAL SETTINGS



    //==================================================================================
    //0.1 CHANNEL SETTINGS
    "channelLanguage": "ru", // (en, ru, de, ... empty if multi)
    //==================================================================================



    //==================================================================================
    //0.2 API KEYS SETTINGS
    "openAIApiKey": "",
    "googleApiKey": "",
    "runpodApiKey": "",
    "productKey": "",
    //==================================================================================



    //==================================================================================
    //0.3 PROXY SERVER SETTINGS
    "proxyServerIP": "45.131.109.151",
    "proxyServerPort": "8001",
    "requestStatusRoute": "request-status",
    "comfyUiRoute": "runpod/comfyui",
    "textAudioAlignerRoute": "runpod/text-audio-align",
    "openAiResponsesRoute": "proxy-responses",
    "openAiImagesRoute": "proxy-openai-images",
    "geminiAiResponsesRoute": "proxy-google-responses",
    "elevenlabsRoute": "proxy-elevenlabs",
    //==================================================================================



    //===================================OVERALL RUNPOD SETTING=========================
    "runpodDashboardPort": 8084,
    "comfyUiPort": 3000,
    // "runpodCountryCodes": [],
    "runpodCountryCodes": ["SE", "RO", "CZ", "IS", "US"],
    //==================================================================================




    //##################################################################################





    //##################################################################################
    //1. VIDEO TEXT GENERATION



    //==================================================================================
    //1.1 VIDEO TEXT GENERATION
    "useClustersLibrary": true,

    "selectClustersPrompt": "Твоя задача - на основе идеи нового ролика и channelClusters выбрать ровно один наиболее подходящий кластер и ровно один основной narrative mode, а затем вернуть один selectedClusterPlan в формате строгого JSON object. На вход ты получаешь: A) topic_idea - тема или идея ролика в свободной формулировке; B) channelClusters - JSON с кластерами канала. Твоя задача - не придумывать новые кластеры, а выбрать только один кластер из уже существующих. Нельзя выбирать несколько кластеров, нельзя смешивать их, нельзя делать blended selection. Нужно выбрать один лучший кластер, который даст самый сильный и самый целостный fit для этой темы. Выбор должен делаться по совокупности признаков: fit_topics, stretch_topics, misfit_topics, self_identity, worldview, pain_growth, fears_desires, common_enemy, language_codes, visual_aesthetics, fit_packaging, fit_narrative_modes, preferred_text_tone, usage_notes. Сначала определи, какой тип ролика скрыт внутри topic_idea: это может быть what is inside, object tour, process/build, life inside, comparison, broad explainer, case studies или другая переносимая рамка. После этого выбери один кластер, который лучше всего подходит не только по теме, но и по психологии подачи, языку, визуалу и упаковке. fit_topics означает прямое хорошее совпадение. stretch_topics означает допустимое совпадение при правильной подаче. misfit_topics означает, что кластер лучше не брать. misfit_topics имеют больший вес, чем stretch_topics. Если тема попадает в misfit_topics кластера, не выбирай его, кроме случая, когда другие поля дают очень сильный fit и misfit выглядит нестрогим. После выбора одного кластера выбери ровно один narrative mode. Выбирать narrative mode нужно только из fit_narrative_modes выбранного кластера. Нельзя выбирать mode, которого нет в fit_narrative_modes выбранного кластера. Narrative mode должен быть один главный, который будет задавать структуру будущего текста. Выбирай его по лучшему совпадению с topic_idea. Примеры логики выбора: если тема про 'что находится внутри', 'как устроено изнутри', 'отсеки', 'части объекта' - обычно лучше single_object_tour; если тема про 'как строится', 'как работает', 'как добывается', 'как доставляется', 'по шагам' - обычно лучше process_explainer; если тема про 'как живут люди внутри', 'быт', 'смены', 'условия жизни' - обычно лучше life_inside_focus; если тема про несколько объектов - top_list; если тема про сравнение - comparison; если тема широкая - broad_explainer; если тема строится на нескольких примерах-кейсах - story_case_studies. Но это только ориентир, а не жесткое правило. selectedClusterPlan нужен для следующего шага генерации текста, метаданных и превью. Поэтому итог должен быть коротким, прикладным и пригодным для машинного использования. Не пересказывай весь channelClusters. Не выводи все кластеры. Не делай длинный анализ. Все поля заполняй только на русском языке, кроме cluster_id и selected_narrative_mode - они должны быть в исходной форме. Верни только JSON object в такой структуре: { 'schema_version': '1.0', 'topic_idea': 'string', 'confidence': 0.0, 'selected_cluster': { 'cluster_id': 'string', 'cluster_label': 'string', 'fit_score': 0.0, 'fit_reason': 'string' }, 'selected_narrative_mode': 'single_object_tour|top_list|process_explainer|comparison|broad_explainer|story_case_studies|life_inside_focus', 'narrative_mode_reason': 'string', 'combined_brief': { 'self_identity': ['string'], 'worldview': ['string'], 'pain_growth': ['string'], 'fears_desires': ['string'], 'common_enemy': ['string'], 'language_codes': ['string'], 'visual_aesthetics': ['string'], 'fit_packaging': ['string'], 'preferred_text_tone': ['string'], 'usage_notes': ['string'], 'avoid_notes': ['string'] } }. Правила заполнения: 1) schema_version всегда '1.0'; 2) confidence - общая уверенность выбора от нуля до единицы; 3) selected_cluster - только один объект; 4) fit_reason - очень короткая причина, почему кластер подходит к теме ролика; 5) narrative_mode_reason - очень короткая причина, почему именно этот narrative mode лучше всего структурирует такую тему; 6) combined_brief - это рабочий бриф для генерации ролика, а не механическая копия всех полей кластера; 7) в combined_brief оставляй только реально полезные сигналы для генерации; 8) usage_notes - короткие практические инструкции, как подавать тему под выбранный кластер и mode; 9) avoid_notes - что точно не делать при генерации текста и упаковки; 10) не добавляй другие поля. Возвращай только валидный JSON object.",

    "videoCreationMode": "singlerequest",

    "videoTextGenService": "openai", //gemini, openai
    "videoTextGenModel": "o3", //gemini-2.5-pro, o3, o4-mini, gpt-4o-mini, etc
    // "videoTextGenModel": "gemini-3.1-pro-preview", //gemini-2.5-pro, o3, o4-mini, gpt-4o-mini, etc

    "wantedTextLength": 30000, //20000 ~= 8500; 30000 ~= 11000-16000
    //==================================================================================



    //==================================================================================
    //1.2 VIDEO TEXT GENERATION MODES SETTINGS
    //SINGLEREQUEST
    "singleRequestSystemPrompt": "Инструкция: Сгенерируй полный текст ролика на основе video_clusters_json и target_length, которые будут переданы в сообщении от роли user; пиши по-русски естественно и разговорно-нейтрально; сохраняй только реальные факты по теме; проверяй и уточняй детали по достоверным источникам в интернете; не выдумывай фактов и не подавай неподтвержденные легенды как истину - если упоминаешь легенду или слух, явно помечай это; общие понятия и термины переводи по контексту, а названия продуктов, моделей, брендов и имена собственные оставляй без изменений; все числа и даты, кроме цифр внутри тегов [pause Ns], пиши словами без сокращений; если сгенерировал цифру, вернись и замени ее словесной формой; держи длину максимально близкой к указанной, допуск около десяти-пятнадцати процентов; длина считается по чистому русскому тексту без учета тегов в квадратных скобках; все измерения указывай в метрической системе; в сообщении user ты получаешь один JSON object video_clusters_json, и ты обязан интерпретировать его так: поле topic_idea - это главная тема ролика; поле selected_narrative_mode - это главный narrative mode и главный структурный каркас текста; поле narrative_mode_reason - поясняет, почему именно этот каркас выбран; поле selected_cluster - это главный выбранный кластер и источник истины о том, под какую аудиторию подается ролик; поле selected_clusters - это вспомогательный список ранее рассмотренных кандидатов, используй его только как дополнительный контекст, но не как основной источник выбора; поле combined_brief - это главный рабочий brief для генерации текста; внутри combined_brief поле self_identity показывает, кем ощущает себя зритель и под чью самоидентификацию нужно подстраивать угол подачи; поле worldview показывает базовые аксиомы зрителя и то, какие выводы должны чувствоваться естественными; поле pain_growth показывает, через какие трудности, усилия, риски и ограничения лучше раскрывать тему; поле fears_desires показывает, какие реальные страхи, желания и мотивы нужно связывать с фактами; поле common_enemy показывает, какая среда, угроза, давление или тип проблемы должен ощущаться как главное препятствие; поле language_codes показывает, какие типы формулировок, словесных акцентов и риторики лучше использовать; поле visual_aesthetics показывает, какие образы и контрасты должны чувствоваться в тексте, чтобы он оправдывал будущую упаковку и визуал; поле fit_packaging показывает, какие акценты должны поддерживаться содержанием, чтобы упаковка не врала; поле recommended_narrative_modes используй только как резервный ориентир, если selected_narrative_mode отсутствует или пуст; поле preferred_text_tone определяет желаемый тон текста; поле usage_notes - это практические инструкции, которым надо следовать; поле avoid_notes - это ошибки и приемы, которых надо строго избегать; если в JSON одновременно есть selected_narrative_mode и recommended_narrative_modes, то главным всегда является selected_narrative_mode; если одновременно есть selected_cluster и selected_clusters, то главным всегда является selected_cluster; если некоторые поля дублируются или частично конфликтуют, используй такой порядок приоритета: фактическая достоверность, topic_idea, selected_narrative_mode, selected_cluster, combined_brief, затем остальные вспомогательные поля; cluster brief не имеет права менять факты, подменять тему или заставлять тебя выдумывать драму, он влияет только на угол подачи, порядок раскрытия, тип акцентов, формулировки, ставки, атмосферу и то, какие реальные детали особенно подчеркивать; используй selected_narrative_mode как основной скелет текста: если single_object_tour - строй текст как проход по одному объекту снаружи внутрь по ключевым зонам и системам, к главной функции, уязвимостям и цене ошибки; если life_inside_focus - строй текст вокруг того, как внутри живут, работают, едят, спят, чинят, терпят и выживают люди, а технические детали подавай как ответ на их бытовые и рабочие риски; если process_explainer - строй текст как последовательность стадий: как строят, как запускают, как работает, как обслуживают, как исправляют отказы, как завершается цикл; если comparison - строй текст через сопоставление подходов, решений или объектов; если top_list - строй текст как подборку нескольких кейсов с ясным отличием каждого; если broad_explainer - строй текст как широкий понятный обзор темы с постепенным углублением; если story_case_studies - строй текст через несколько конкретных кейсов, где каждый раскрывает отдельный аспект темы; combined_brief используй прикладно: worldview должен чувствоваться в выборе акцентов и формулировок, но не превращаться в лозунги; fears_desires связывай с реальными последствиями для людей, времени, безопасности, цены ошибки, автономности, контроля, удобства, статуса и выживания; common_enemy используй как естественное препятствие или давление среды, а не как карикатурного врага; language_codes вплетай мягко и естественно, а не механически; visual_aesthetics и fit_packaging используй для выбора образов и акцентов, чтобы содержание ролика оправдывало упаковку; usage_notes соблюдай; avoid_notes соблюдай строго; формат подачи держи как подборку интересных фактов: текст состоит из автономных абзацев-микросцен, каждый абзац - один законченный факт с кратким пояснением зачем это важно и одной-двумя конкретиками; между абзацами - мягкие смысловые мостики; без нумерации и маркеров списков; избегай жестких шаблонов и меню вариантов; общий порядок абзацев должен подчиняться selected_narrative_mode; начинай с ясной интриги или парадокса без затянутого вступления; мягко обещай важное раскрытие впереди и веди к нему через меняющийся ритм сцен и фактов; поддерживай ощущение незавершенности: изредка задавай вопрос, на который ответ появится позже, но не превращай текст в механический вопрос-ответ; делай ставки конкретными - связывай факты с последствиями для людей, времени, денег и репутации, показывай цену ошибки и цену выбора; пиши как для озвучки: короткие